worker_processes  1;
error_log  logs/error.log  info;

events {
    worker_connections  1024;
}

http {
    lua_package_path "/usr/local/openresty/lualib/?.lua;/etc/nginx/lua/?.lua;;";
    lua_package_cpath "/usr/local/openresty/lualib/?.so;;";

    lua_shared_dict redis_pool_dict 10m;

    server {
        listen 8080;
        server_name localhost;

        location /load_plugin {
            lua_code_cache off;

            content_by_lua_block {
                ngx.req.read_body()

                local redis_host = "127.0.0.1"
                local redis_port = 6379
                local redis_pool_name = "my_redis_pool"
                local redis_pool_size = 100
                local redis_pool_idle_timeout = 10000

                local code_source = ngx.var.arg_source or "header"
                local redis_key = ngx.var.arg_key or "dynamic_plugin:default"

                local plugin_code = nil

                if code_source == "header" then
                    plugin_code = ngx.req.get_headers()["X-Lua-Plugin-Code"]
                    if plugin_code then
                        ngx.log(ngx.INFO, "Plugin code received from HTTP header 'X-Lua-Plugin-Code'.")
                    end
                elseif code_source == "redis" then
                    local redis = require "resty.redis"
                    local red = redis:new()

                    red:set_timeout(1000)

                    local ok, err = red:connect(redis_host, redis_port, redis_pool_name, redis_pool_size, redis_pool_idle_timeout)
                    if not ok then
                        ngx.log(ngx.ERR, "failed to connect to redis (pool: ", redis_pool_name, "): ", err)
                        ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
                        return
                    end

                    local res, err = red:get(redis_key)
                    if not res then
                        ngx.log(ngx.ERR, "failed to get plugin code from redis key '", redis_key, "': ", err)
                        ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
                        return
                    end

                    if res == ngx.null then
                        ngx.log(ngx.INFO, "Redis key '", redis_key, "' not found.")
                    else
                        plugin_code = res
                        ngx.log(ngx.INFO, "Plugin code received from Redis key '", redis_key, "'.")
                    end

                    local ok, err = red:set_keepalive(redis_pool_idle_timeout, redis_pool_size)
                    if not ok then
                        ngx.log(ngx.WARN, "failed to set keepalive for redis (pool: ", redis_pool_name, "): ", err)
                    end
                end

                if not plugin_code then
                    ngx.status = ngx.HTTP_NOT_FOUND
                    ngx.say("No plugin code provided. Check 'X-Lua-Plugin-Code' header for source='header' or Redis key '", redis_key, "' for source='redis'.")
                    return
                end

                ngx.log(ngx.INFO, "Attempting to load and execute plugin code (", string.len(plugin_code), " bytes).")

                local func, err = loadstring(plugin_code)
                if not func then
                    ngx.status = ngx.HTTP_BAD_REQUEST
                    ngx.say("Failed to compile plugin code: ", err)
                    ngx.log(ngx.ERR, "Failed to compile plugin code: ", err)
                    return
                end

                local ok, res = pcall(func)
                if not ok then
                    ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
                    ngx.say("Failed to execute plugin: ", res)
                    ngx.log(ngx.ERR, "Failed to execute plugin: ", res)
                    return
                end

                ngx.status = ngx.HTTP_OK
                ngx.header["Content-Type"] = "text/plain"

                if res ~= nil then
