                        ngx.say("Plugin executed successfully. Result (tostring): ", tostring(res))
                    else
                        ngx.say("Plugin executed successfully. Result: ", res)
                    end
                else
                    ngx.say("Plugin executed successfully. No specific return value.")
                end
                ngx.log(ngx.INFO, "Plugin executed successfully.")
            }
        }

        location /api/status {
            content_by_lua_block {
                ngx.say("API Status: OK. Load plugins via /load_plugin.")
            }
        }
